import React, { useEffect, useRef } from 'react';
import '../styles/components/Skills.css';

const Skills = () => {
  const sectionRef = useRef(null);
  const [isVisible, setIsVisible] = React.useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => {
      if (sectionRef.current) {
        observer.unobserve(sectionRef.current);
      }
    };
  }, []);

  const languages = [
    { name: 'Python', level: 'intermediate/expert' },
    { name: 'HTML', level: 'intermediate (not really a coding language)' },
    { name: 'CSS', level: 'intermediate (not really a coding language)' },
    { name: 'JavaScript', level: 'noob/intermediate' },
    { name: 'TypeScript', level: 'noob' },
    { name: 'SQL', level: 'noob' },
    { name: 'Docker', level: 'intermediate' },
    { name: 'Git', level: 'expert (git is easy)' },
    { name: 'C#', level: 'noob' },
    { name: 'C++', level: 'i don\'t know what i\'m even doing 😭' },
    { name: 'Assembly', level: '💀' }
  ];

  return (
    <section id="skills" className="skills section" ref={sectionRef}>
      <div className="container">
        <h2 className="section-title">Skills & Technologies</h2>
        <div className={`skills-grid ${isVisible ? 'visible' : ''}`}>
          {skillCategories.map((category, categoryIndex) => (
            <div key={category.title} className="skill-category glass">
              <h3 className="category-title">{category.title}</h3>
              <div className="skills-list">
                {category.skills.map((skill, skillIndex) => (
                  <div key={skill.name} className="skill-item">
                    <div className="skill-header">
                      <span className="skill-name">{skill.name}</span>
                      <span className="skill-percentage">{skill.level}%</span>
                    </div>
                    <div className="skill-bar">
                      <div 
                        className="skill-progress"
                        style={{ 
                          width: isVisible ? `${skill.level}%` : '0%',
                          transitionDelay: `${(categoryIndex * 0.1) + (skillIndex * 0.05)}s`
                        }}
                      ></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Skills;
